        TO_OBTAIN_YOU_MUST_SEEK_OUT_JOACHIM_HE                                 = 7366,  -- To obtain %, you must seek out Joachim. He is currently a resident of your world, Vana'diel.
        LASTLY_I_WILL_EXPLAIN_IN_DETAIL_THE_MYRIAD                             = 7367,  -- Lastly, I will explain in detail the myriad effects granted by the visitant status.
        MANY_ARE_THE_REPORTS_OF_POSITIVE_THINGS_OCCURRING                      = 7368,  -- Many are the reports of positive things occurring while under its auspices, from a general upturn in fortunes to more specific benefits such as accelerated growth and greater ease of cruor harvesting.
        NATURALLY_THESE_BENEFITS_WILL_NOT_COME_TO_THE                          = 7369,  -- Naturally, these benefits will not come to the idle. The gains have been observed to grow proportionately to one's exploits in Abyssea.
        ALL_GOOD_THINGS_COME_TO_AN_END_HOWEVER                                 = 7370,  -- All good things come to an end, however, and this is no exception. The effects endure as long as you remain in Abyssea, but will wear off at the instant of your departure.
