        ANCIENT_ABYSSITE_HAS_BEEN_OBSERVED_TO_IMPROVE_THE                      = 7388,  -- Ancient abyssite has been observed to improve the fortunes and vitality of their possessors, not unlike a good luck talisman.
        THE_MOST_POPULAR_VARIETIES_OFFER_EXTENDED_VISITANT_STATUS              = 7389,  -- The most popular varieties offer extended visitant status time, accelerated growth, and myriad enhancement effects. Some are even said to improve luck, but such benefits can be troublesome to measure.
        I_AM_LIMITED_IN_THE_TYPES_OF_ANCIENT                                   = 7390,  -- I am limited in the types of ancient abyssite I can issue. The opportunity to acquire rarer varieties, however, will surely visit you during your time in Abyssea.
