        THESE_MARTELLOS_ARE_DEFENSIVE_FORTIFICATIONS_DEVELOPED_BY_THE          = 8097,  -- These martellos are defensive fortifications developed by the resistance to aid in our battle against the fell hordes. Enchanted structures, they may be employed to restore your health and magic, cure ailments, and generally restore you to fighting trim.
        I_HAVE_BEEN_ENTRUSTED_WITH_THE_SUPERVISION_AND                         = 8098,  -- I have been entrusted with the supervision and maintenance of these martellos...but this is none of your concern.
        I_HAVE_BEEN_ENTRUSTED_WITH_THE_SUPERVISION_AND_2                       = 8099,  -- I have been entrusted with the supervision and maintenance of these martellos. Would you be needing something of me?
        NEED_SOMETHING_ASSIST_WITH_REPLENISHMENT_ASSIST_WITH_UPGRADES          = 8100,  -- Need something? Assist with replenishment. Assist with upgrades. Martellos? Come again? Nothing in particular.
        SPLENDID_YOUR_AID_IS_A_GREAT_BOON_TO                                   = 8101,  -- Splendid! Your aid is a great boon to the resistance effort. To replenish a martello, you'll need to insert one of these % into the structure.
        BE_FOREWARNED_YOU_WILL_BE_UNABLE_TO_CARRY                              = 8102,  -- Be forewarned: you will be unable to carry these and % at the same time.
        TAKE_ALONG_THE_YES_NO                                                  = 8103,  -- Take along the %? Yes. No.
        WE_WOULD_BE_PARTICULARLY_INDEBTED_TO_YOU_FOR                           = 8104,  -- We would be particularly indebted to you for efficient replenishment of martellos in remote locations. Best of luck in your efforts!
        WHY_IS_THAT_NOT_ALREADY_IN_YOUR_POSSSESION                             = 8105,  -- Why, is that not % already in your posssesion? You need only insert that into a martello to initiate replenishment.
        I_SEE_THAT_YOU_CURRENTLY_POSSESS_DO_YOU                                = 8106,  -- I see that you currently possess %. Do you wish to abandon your upgrading efforts and participate in replenishment instead?
        YOU_RETURN_THE_AND_OBTAIN_IN_ITS_STEAD                                 = 8107,  -- You return the % and obtain % in its stead!
        YOUR_SUPPORT_IS_MOST_HEARTENING_IN_THESE_DARK                          = 8108,  -- Your support is most heartening in these dark times. Upgrading a martello will require you to attach a device known as %.
        MIND_YOU_THE_DEVICE_IS_RATHER_UNWIELDY_YOU                             = 8109,  -- Mind you, the device is rather unwieldy. You will not be able to carry it and % at the same time.
        EXCELLENT_I_WOULD_BE_ESPECIALLY_APPRECIATIVE_IF_YOU                    = 8110,  -- Excellent. I would be especially appreciative if you could upgrade those martellos in distant locations--the quicker the better. Be careful out there!
